			assert(paths.indexOf('@nodebb/nodebb-plugin-abc') > -1);

			plugins.nodeModulesPath = nodeModulesPath;
			done();
		});
	});

	it('should submit usage info', (done) => {
		plugins.submitUsageData((err) => {
			assert.ifError(err);
			done();
		});
	});

